def convert_list_dictionary(l1, l2, l3):
    """Convert three lists into one nested dictionary.

    Each item from l1 becomes a top-level key. The corresponding items from
    l2 and l3 are combined as an inner key/value pair.
    """
    result = {}
    for x, y, z in zip(l1, l2, l3):
        result[x] = {y: z}
    return result

